  var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(CONFIG_PEDIDOS_PARCIAIS.abaDestino);
  if (!sheet) return Logger.log("Aba não existe.");
  Logger.log("Total de pedidos na aba: " + (sheet.getLastRow() - 1));
}

